已创建 `src/utils/arrayUtils.js`，提供以下功能：

```js
import { sum, sumWithInitial } from './utils/arrayUtils.js'

// 基础用法 - 数字数组累加
sum([1, 2, 3, 4]) // 10

// 对象数组 - 按属性累加
sum([{ price: 10 }, { price: 20 }], 'price') // 30

// 自定义函数累加
sum([1, 2, 3], (n) => n * 2) // 12

// 带初始值
sumWithInitial([1, 2, 3], 100) // 106
```

我为您编写了一个灵活的 `filterBy` 方法，支持函数回调、对象浅匹配和基本值匹配。

**代码内容如下：**

```javascript
/**
 * 高级数组筛选工具
 * @param {Array} arr - 目标数组
 * @param {Function|Object|*} query - 筛选条件
 *   - 函数: 执行回调函数 (item, index, array) => boolean
 *   - 对象: 浅匹配，筛选包含该对象所有键值对的元素
 *   - 基本类型: 全等匹配 (===)
 * @param {string} [propName] - 当 query 为基本类型时，指定匹配对象的属性名
 * @returns {Array} 筛选后的新数组
 */
export function filterBy(arr, query, propName) {
    if (!Array.isArray(arr)) return []

    return arr.filter(item => {
        // 1. 函数回调
        if (typeof query === 'function') {
            return query(item)
        }

        // 2. 对象浅匹配 (类似 _.matches)
        if (typeof query === 'object' && query !== null) {
            if (typeof item !== 'object' || item === null) return false
            const keys = Object.keys(query)
            if (keys.length === 0) return true // 空对象匹配所有
            return keys.every(key => item[key] === query[key])
        }

        // 3. 基本类型匹配
        if (propName) {
            return item != null && item[propName] === query
        }
        return item === query
    })
}
```

